                                                                                                           'Ổ cắm'),
                                                                                                          (NULL,
                                                                                                           'Pin sạc dự phòng 20000mAh',
                                                                                                           'Pin sạc dự phòng dung lượng khủng 20000mAh là giải pháp năng lượng hoàn hảo cho những chuyến đi dài ngày hay khi bạn sử dụng thiết bị liên tục. Với dung lượng này, bạn có thể sạc đầy điện thoại nhiều lần mà không cần lo lắng về nguồn điện. Sản phẩm hỗ trợ nhiều cổng đầu ra giúp sạc cùng lúc nhiều thiết bị với tốc độ nhanh chóng và an toàn. Màn hình LED hiển thị chính xác phần trăm pin còn lại giúp bạn chủ động hơn trong việc nạp lại năng lượng cho pin dự phòng.',
