                                                                                                           'Áo khoác'),
                                                                                                          (NULL,
                                                                                                           'Chuột văn phòng',
                                                                                                           'Chuột văn phòng được thiết kế tối ưu cho các công việc hành chính hàng ngày với kích thước vừa vặn và độ nhạy mắt đọc ổn định. Sản phẩm hỗ trợ tốt cho việc duyệt văn bản, bảng tính Excel và lướt web mượt mà. Nút bấm của chuột có độ nảy tốt nhưng không gây tiếng ồn lớn, giúp giữ không gian làm việc yên tĩnh cho đồng nghiệp xung quanh. Chất liệu nhựa ABS cao cấp có bề mặt chống bám mồ hôi, giúp bạn sử dụng liên tục trong nhiều giờ mà vẫn cảm thấy thoải mái và sạch sẽ nhất.',
                                                                                                           250000, 50,
