                                                                                                           'Chuột'),
                                                                                                          (NULL,
                                                                                                           'Bàn phím giả cơ',
                                                                                                           'Bàn phím giả cơ là sự lựa chọn tuyệt vời cho những ai muốn trải nghiệm cảm giác gõ phím của bàn phím cơ nhưng với mức giá dễ tiếp cận hơn. Các phím bấm được thiết kế cao, mang lại hành trình phím sâu và tiếng click nhẹ nhàng đầy phấn khích. Hệ thống đèn LED nền rực rỡ giúp bạn làm việc hay giải trí hiệu quả hơn trong môi trường thiếu sáng. Sản phẩm có độ bền cao, tích hợp các phím tắt đa phương tiện tiện lợi, là phụ kiện không thể thiếu để trang trí và nâng cấp góc học tập của bạn.',
                                                                                                           890000, 20,
